const MAKES=Object.keys(VM).sort();const CY=new Date().getFullYear();const YEARS=Array.from({length:46},(_,i)=>CY+1-i);
function nY(y){return y<100?(y<50?2000+y:1900+y):y}
function gMk(yr){const y=parseInt(yr);return MAKES.filter(m=>VM[m].some(([,s,e])=>y>=nY(s)&&y<=nY(e)));}
function gMd(mk,yr){const y=parseInt(yr);return(VM[mk]||[]).filter(([,s,e])=>y>=nY(s)&&y<=nY(e)).map(([n])=>n).sort();}

